                                 <el-option value=\"Detallado\" label=\"Detallado\"></el-option>\r\n                                    <el-option value=\"Resumen\" label=\"Resumen\"></el-option>\r\n                                </el-select>\r\n                            </div>\r\n                        </div> -->\r\n                        <div class=\"col-lg-4 col-md-4 col-md-4 col-sm-12 d-flex align-items-center\">\r\n                            <el-button class=\"submit\" type=\"primary\" @click.prevent=\"getRecordsByFilter\" :loading=\"loading_submit\" icon=\"el-icon-search\" >Buscar</el-button>\r\n                            <template v-if=\"records.length>0\">\r\n\r\n                                <!-- <el-button class=\"submit\" type=\"danger\" @click.prevent=\"clickDownload('pdf')\"><i class=\"fa fa-file-pdf\" ></i>  Exportal PDF</el-button> -->\r\n                                <el-button class=\"submit\" type=\"success\" @click.prevent=\"clickDownload('excel')\"><i class=\"fa fa-file-excel\" ></i>  Exportal Excel</el-button>\r\n                            </template>\r\n\r\n                        </div>\r\n                </div>\r\n            </div>\r\n\r\n\r\n            <div class=\"col-md-12\">\r\n                <div class=\"table-responsive\">\r\n                    <table class=\"table\">\r\n                        <thead>\r\n                        <slot name=\"heading\"></slot>\r\n                        </thead>\r\n                        <tbody>\r\n                            <slot v-for=\"(row, index) in records\" :row=\"row\" :index=\"customIndex(index)\"></slot>\r\n                        </tbody>\r\n                    </table>\r\n                    <div>\r\n                        <el-pagination\r\n                                @current-change=\"getRecords\"\r\n                                layout=\"total, prev, pager, next\"\r\n                                :total=\"pagination.total\"\r\n                                :current-page.sync=\"pagination.current_page\"\r\n                                :page-size=\"pagination.per_page\">\r\n                        </el-pagination>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n\r\n    </div>\r\n</template>\r\n<style>\r\n.font-custom{\r\n    font-size:15px !important\r\n}\r\n</style>\r\n<script>\r\n\r\n    import moment from 'moment'\r\n    import queryString from 'query-string'\r\n\r\n    export default {\r\n        props: {\r\n            resource: String,\r\n        },\r\n        data () {\r\n            return {\r\n                loading_submit:false,\r\n                loading_search:false,\r\n                columns: [],\r\n                records: [],\r\n                pagination: {},\r\n                search: {},\r\n                totals: {},\r\n                categories: [],\r\n                warehouses: [],\r\n                form: {},\r\n            }\r\n        },\r\n        computed: {\r\n        },\r\n        created() {\r\n            this.initForm()\r\n            this.$eventHub.$on('reloadData', () => {\r\n                this.getRecords()\r\n            })\r\n        },\r\n\r\n        async mounted () {\r\n            await this.$http.get(`/${this.resource}/tables`)\r\n                .then(response => {\r\n                    this.warehouses = response.data.warehouses;\r\n                    this.categories=response.data.categories;\r\n                });\r\n\r\n             await this.getRecords()\r\n        },\r\n        methods: {\r\n            async clickDownload(type) {\r\n                let query = queryString.stringify({\r\n                    ...this.form\r\n                });\r\n                if(type==\"pdf\"){\r\n                    window.open(`/${this.resource}/${type}/?${query}`, '_blank');\r\n                }else{\r\n                    // console.log(`/${this.resource}/${type}?${query}`);\r\n                    const response = await this.$http.get(`/${this.resource}/${type}/?${query}`, { responseType: \"blob\" });\r\n                    const blob = new Blob([response.data], { type: \"application/vnd.openxmlformats-officedocument.spreadsheetml.sheet\" });\r\n                    const link = document.createElement(\"a\");\r\n                    link.href = URL.createObjectURL(blob);\r\n                    link.download = \"Reporte_Inv\";\r\n                    link.click();\r\n                    URL.revokeObjectURL(link.href);\r\n                }\r\n            },\r\n            initForm(){\r\n\r\n                this.form = {\r\n                    warehouse_id: null,\r\n                    category_id: null,\r\n                    typeresult:'Detallado'\r\n                }\r\n\r\n            },\r\n            customIndex(index) {\r\n                return (this.pagination.per_page * (this.pagination.current_page - 1)) + index + 1\r\n            },\r\n            async getRecordsByFilter(){\r\n\r\n                this.loading_submit = await true\r\n                await this.getRecords()\r\n                this.loading_submit = await false\r\n\r\n            },\r\n            getRecords() {\r\n                return this.$http.get(`/${this.resource}/records?${this.getQueryParameters()}`).then((response) => {\r\n                    this.records = response.data.data\r\n                    this.records = this.records.map(r=>({\r\n                        ...r,\r\n                        realStock:r.stock\r\n                    }));\r\n                    \r\n                    this.pagination = response.data.meta\r\n                    this.pagination.per_page = parseInt(response.data.meta.per_page)\r\n                    this.loading_submit = false\r\n                    // this.initTotals()\r\n                });\r\n\r\n\r\n            },\r\n            getQueryParameters() {\r\n                return queryString.stringify({\r\n                    page: this.pagination.current_page,\r\n                    limit: this.limit,\r\n                    ...this.form\r\n                })\r\n            },\r\n\r\n            changeDisabledDates() {\r\n                if (this.form.date_end < this.form.date_start) {\r\n                    this.form.date_end = this.form.date_start\r\n                }\r\n                // this.loadAll();\r\n            },\r\n            changeDisabledMonths() {\r\n                if (this.form.month_end < this.form.month_start) {\r\n                    this.form.month_end = this.form.month_start\r\n                }\r\n                // this.loadAll();\r\n            },\r\n            changePeriod() {\r\n                if(this.form.period === 'month') {\r\n                    this.form.month_start = moment().format('YYYY-MM');\r\n                    this.form.month_end = moment().format('YYYY-MM');\r\n                }\r\n                if(this.form.period === 'between_months') {\r\n                    this.form.month_start = moment().startOf('year').format('YYYY-MM'); //'2019-01';\r\n                    this.form.month_end = moment().endOf('year').format('YYYY-MM');;\r\n                }\r\n                if(this.form.period === 'date') {\r\n                    this.form.date_start = moment().format('YYYY-MM-DD');\r\n                    this.form.date_end = moment().format('YYYY-MM-DD');\r\n                }\r\n                if(this.form.period === 'between_dates') {\r\n                    this.form.date_start = moment().startOf('month').format('YYYY-MM-DD');\r\n                    this.form.date_end = moment().endOf('month').format('YYYY-MM-DD');\r\n                }\r\n                // this.loadAll();\r\n            },\r\n        }\r\n    }\r\n</script>\r\n"],"sourceRoot":""}]);

